#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, A; scanf("%d %d", &N, &A);
        int ans = A < (N - A) ? A : (N - A);
        printf("%d\n", ans);
    }
    return 0;
}

